"""
Parameterized generator for GH1126_autogluon_4899.

Source PR:    https://github.com/autogluon/autogluon/pull/4899
Source Issue: N/A

Seed varies: renames 'absolute' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1126_autogluon_4899'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1126_autogluon_4899'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('absolute', 'absolute' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1126_autogluon_4899',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'autogluon/autogluon',
                "pr_number": 4899,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/autogluon/autogluon/pull/4899",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'timeseries/src/autogluon/timeseries/models/gluonts/torch/models.py': '"""\nModule including wrappers for PyTorch implementations of models in GluonTS\n"""\n\nimport logging\nfrom typing import Any, Dict, Type\n\nfrom gluonts.model.estimator import Estimator as GluonTSEstimator\n\nfrom autogluon.timeseries.models.gluonts.abstract_gluonts import AbstractGluonTSModel\nfrom autogluon.timeseries.utils.datetime import (\n    get_lags_for_frequency,\n    get_seasonality,\n    get_time_features_for_frequency,\n)\n\n# NOTE: We avoid imports for torch and lightning.pytorch at the top level and hide them inside class methods.\n# This is done to skip these imports during multiprocessing (which may cause bugs)\n\n# FIXME: introduces cpflows dependency. We exclude this model until a future release.\n# from gluonts.torch.model.mqf2 import MQF2MultiHorizonEstimator\n\n# FIXME: DeepNPTS does not implement the GluonTS PyTorch API, and does not use\n# PyTorch Lightning. We exclude this model until a future release.\n# from gluonts.torch.model.deep_npts import DeepNPTSEstimator\n\n\nlogger = logging.getLogger(__name__)\n\n\nclass DeepARModel(AbstractGluonTSModel):\n    """Autoregressive forecasting model based on a recurrent neural network [Salinas2020]_.\n\n    Based on `gluonts.torch.model.deepar.DeepAREstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.deepar.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n\n    References\n    ----------\n    .. [Salinas2020] Salinas, David, et al.\n        "DeepAR: Probabilistic forecasting with autoregressive recurrent networks."\n        International Journal of Forecasting. 2020.\n\n\n    Other Parameters\n    ----------------\n    context_length : int, default = max(10, 2 * prediction_length)\n        Number of steps to unroll the RNN for before computing predictions\n    disable_static_features : bool, default = False\n        If True, static features won\'t be used by the model even if they are present in the dataset.\n        If False, static features will be used by the model if they are present in the dataset.\n    disable_known_covariates : bool, default = False\n        If True, known covariates won\'t be used by the model even if they are present in the dataset.\n        If False, known covariates will be used by the model if they are present in the dataset.\n    num_layers : int, default = 2\n        Number of RNN layers\n    hidden_size : int, default = 40\n        Number of RNN cells for each layer\n    dropout_rate : float, default = 0.1\n        Dropout regularization parameter\n    embedding_dimension : int, optional\n        Dimension of the embeddings for categorical features\n        (if None, defaults to [min(50, (cat+1)//2) for cat in cardinality])\n    max_cat_cardinality : int, default = 100\n        Maximum number of dimensions to use when one-hot-encoding categorical known_covariates.\n    distr_output : gluonts.torch.distributions.DistributionOutput, default = StudentTOutput()\n        Distribution to use to evaluate observations and sample predictions\n    scaling: bool, default = True\n        If True, mean absolute scaling will be applied to each *context window* during training & prediction.\n        Note that this is different from the `target_scaler` that is applied to the *entire time series*.\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 64\n        Size of batches used during training\n    predict_batch_size : int, default = 500\n        Size of batches used during prediction.\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-3,\n        Learning rate used during training\n    trainer_kwargs : dict, optional\n        Optional keyword arguments passed to ``lightning.Trainer``.\n    early_stopping_patience : int or None, default = 20\n        Early stop training if the validation loss doesn\'t improve for this many epochs.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    # TODO: Replace "scaling: bool" with "window_scaler": {"mean_abs", None} for consistency?\n\n    _supports_known_covariates = True\n    _supports_static_features = True\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.deepar import DeepAREstimator\n\n        return DeepAREstimator\n\n    def _get_estimator_init_args(self) -> Dict[str, Any]:\n        init_kwargs = super()._get_estimator_init_args()\n        init_kwargs["num_feat_static_cat"] = self.num_feat_static_cat\n        init_kwargs["num_feat_static_real"] = self.num_feat_static_real\n        init_kwargs["cardinality"] = self.feat_static_cat_cardinality\n        init_kwargs["num_feat_dynamic_real"] = self.num_feat_dynamic_real\n        init_kwargs.setdefault("lags_seq", get_lags_for_frequency(self.freq))\n        init_kwargs.setdefault("time_features", get_time_features_for_frequency(self.freq))\n        return init_kwargs\n\n\nclass SimpleFeedForwardModel(AbstractGluonTSModel):\n    """Simple feedforward neural network that simultaneously predicts all future values.\n\n    Based on `gluonts.torch.model.simple_feedforward.SimpleFeedForwardEstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.simple_feedforward.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n\n    Other Parameters\n    ----------------\n    context_length : int, default = max(10, 2 * prediction_length)\n        Number of time units that condition the predictions\n    hidden_dimensions: List[int], default = [20, 20]\n        Size of hidden layers in the feedforward network\n    distr_output : gluonts.torch.distributions.DistributionOutput, default = StudentTOutput()\n        Distribution to fit.\n    batch_normalization : bool, default = False\n        Whether to use batch normalization\n    mean_scaling : bool, default = True\n        If True, mean absolute scaling will be applied to each *context window* during training & prediction.\n        Note that this is different from the `target_scaler` that is applied to the *entire time series*.\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 64\n        Size of batches used during training\n    predict_batch_size : int, default = 500\n        Size of batches used during prediction.\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-3,\n        Learning rate used during training\n    trainer_kwargs : dict, optional\n        Optional keyword arguments passed to ``lightning.Trainer``.\n    early_stopping_patience : int or None, default = 20\n        Early stop training if the validation loss doesn\'t improve for this many epochs.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.simple_feedforward import SimpleFeedForwardEstimator\n\n        return SimpleFeedForwardEstimator\n\n\nclass TemporalFusionTransformerModel(AbstractGluonTSModel):\n    """Combines LSTM with a transformer layer to predict the quantiles of all future target values [Lim2021]_.\n\n    Based on `gluonts.torch.model.tft.TemporalFusionTransformerEstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.tft.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n\n    References\n    ----------\n    .. [Lim2021] Lim, Bryan, et al.\n        "Temporal Fusion Transformers for Interpretable Multi-horizon Time Series Forecasting."\n        International Journal of Forecasting. 2021.\n\n\n    Other Parameters\n    ----------------\n    context_length : int, default = max(64, 2 * prediction_length)\n        Number of past values used for prediction.\n    disable_static_features : bool, default = False\n        If True, static features won\'t be used by the model even if they are present in the dataset.\n        If False, static features will be used by the model if they are present in the dataset.\n    disable_known_covariates : bool, default = False\n        If True, known covariates won\'t be used by the model even if they are present in the dataset.\n        If False, known covariates will be used by the model if they are present in the dataset.\n    disable_past_covariates : bool, default = False\n        If True, past covariates won\'t be used by the model even if they are present in the dataset.\n        If False, past covariates will be used by the model if they are present in the dataset.\n    hidden_dim : int, default = 32\n        Size of the LSTM & transformer hidden states.\n    variable_dim : int, default = 32\n        Size of the feature embeddings.\n    num_heads : int, default = 4\n        Number of attention heads in self-attention layer in the decoder.\n    dropout_rate : float, default = 0.1\n        Dropout regularization parameter\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 64\n        Size of batches used during training\n    predict_batch_size : int, default = 500\n        Size of batches used during prediction.\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-3,\n        Learning rate used during training\n    trainer_kwargs : dict, optional\n        Optional keyword arguments passed to ``lightning.Trainer``.\n    early_stopping_patience : int or None, default = 20\n        Early stop training if the validation loss doesn\'t improve for this many epochs.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    _supports_known_covariates = True\n    _supports_past_covariates = True\n    _supports_cat_covariates = True\n    _supports_static_features = True\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.tft import TemporalFusionTransformerEstimator\n\n        return TemporalFusionTransformerEstimator\n\n    def _get_default_params(self):\n        return super()._get_default_params() | {\n            "context_length": min(512, max(64, 2 * self.prediction_length)),\n        }\n\n    def _get_estimator_init_args(self) -> Dict[str, Any]:\n        init_kwargs = super()._get_estimator_init_args()\n        if self.num_feat_dynamic_real > 0:\n            init_kwargs["dynamic_dims"] = [self.num_feat_dynamic_real]\n        if self.num_past_feat_dynamic_real > 0:\n            init_kwargs["past_dynamic_dims"] = [self.num_past_feat_dynamic_real]\n        if self.num_feat_static_real > 0:\n            init_kwargs["static_dims"] = [self.num_feat_static_real]\n        if len(self.feat_static_cat_cardinality):\n            init_kwargs["static_cardinalities"] = self.feat_static_cat_cardinality\n        if len(self.feat_dynamic_cat_cardinality):\n            init_kwargs["dynamic_cardinalities"] = self.feat_dynamic_cat_cardinality\n        if len(self.past_feat_dynamic_cat_cardinality):\n            init_kwargs["past_dynamic_cardinalities"] = self.past_feat_dynamic_cat_cardinality\n\n        init_kwargs.setdefault("time_features", get_time_features_for_frequency(self.freq))\n        return init_kwargs\n\n\nclass DLinearModel(AbstractGluonTSModel):\n    """Simple feedforward neural network that subtracts trend before forecasting [Zeng2023]_.\n\n    Based on `gluonts.torch.model.d_linear.DLinearEstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.d_linear.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n    References\n    ----------\n    .. [Zeng2023] Zeng, Ailing, et al.\n        "Are transformers effective for time series forecasting?"\n        AAAI Conference on Artificial Intelligence. 2023.\n\n    Other Parameters\n    ----------------\n    context_length : int, default = 96\n        Number of time units that condition the predictions\n    hidden_dimension: int, default = 20\n        Size of hidden layers in the feedforward network\n    distr_output : gluonts.torch.distributions.DistributionOutput, default = StudentTOutput()\n        Distribution to fit.\n    scaling : {"mean", "std", None}, default = "mean"\n        Scaling applied to each *context window* during training & prediction.\n        One of ``"mean"`` (mean absolute scaling), ``"std"`` (standardization), ``None`` (no scaling).\n\n        Note that this is different from the `target_scaler` that is applied to the *entire time series*.\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 64\n        Size of batches used during training\n    predict_batch_size : int, default = 500\n        Size of batches used during prediction.\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-3,\n        Learning rate used during training\n    trainer_kwargs : dict, optional\n        Optional keyword arguments passed to ``lightning.Trainer``.\n    early_stopping_patience : int or None, default = 20\n        Early stop training if the validation loss doesn\'t improve for this many epochs.\n    weight_decay : float, default = 1e-8\n        Weight decay regularization parameter.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    def _get_default_params(self):\n        return super()._get_default_params() | {\n            "context_length": 96,\n        }\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.d_linear import DLinearEstimator\n\n        return DLinearEstimator\n\n\nclass PatchTSTModel(AbstractGluonTSModel):\n    """Transformer-based forecaster that segments each time series into patches [Nie2023]_.\n\n    Based on `gluonts.torch.model.d_linear.PatchTSTEstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.patch_tst.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n    References\n    ----------\n    .. [Nie2023] Nie, Yuqi, et al.\n        "A Time Series is Worth 64 Words: Long-term Forecasting with Transformers."\n        International Conference on Learning Representations. 2023.\n\n    Other Parameters\n    ----------------\n    context_length : int, default = 96\n        Number of time units that condition the predictions\n    patch_len : int, default = 16\n        Length of the patch.\n    stride : int, default = 8\n        Stride of the patch.\n    d_model : int, default = 32\n        Size of hidden layers in the Transformer encoder.\n    nhead : int, default = 4\n        Number of attention heads in the Transformer encoder which must divide d_model.\n    num_encoder_layers : int, default = 2\n        Number of layers in the Transformer encoder.\n    distr_output : gluonts.torch.distributions.DistributionOutput, default = StudentTOutput()\n        Distribution to fit.\n    scaling : {"mean", "std", None}, default = "mean"\n        Scaling applied to each *context window* during training & prediction.\n        One of ``"mean"`` (mean absolute scaling), ``"std"`` (standardization), ``None`` (no scaling).\n\n        Note that this is different from the `target_scaler` that is applied to the *entire time series*.\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 64\n        Size of batches used during training\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-3,\n        Learning rate used during training\n    weight_decay : float, default = 1e-8\n        Weight decay regularization parameter.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    _supports_known_covariates = True\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.patch_tst import PatchTSTEstimator\n\n        return PatchTSTEstimator\n\n    def _get_default_params(self):\n        return super()._get_default_params() | {"context_length": 96, "patch_len": 16}\n\n    def _get_estimator_init_args(self) -> Dict[str, Any]:\n        init_kwargs = super()._get_estimator_init_args()\n        init_kwargs["num_feat_dynamic_real"] = self.num_feat_dynamic_real\n        return init_kwargs\n\n\nclass WaveNetModel(AbstractGluonTSModel):\n    """WaveNet estimator that uses the architecture proposed in [Oord2016]_ with quantized targets.\n\n    The model is based on a CNN architecture with dilated convolutions. Time series values are quantized into buckets\n    and the model is trained using the cross-entropy loss.\n\n    Based on `gluonts.torch.model.wavenet.WaveNetEstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.wavenet.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n    References\n    ----------\n    .. [Oord2016] Oord, Aaron van den, et al.\n        "Wavenet: A generative model for raw audio"\n        arXiv preprint arXiv:1609.03499. 2016.\n\n    Other Parameters\n    ----------------\n    num_bins : int, default = 1024\n        Number of bins used for quantization of the time series.\n    num_residual_channels : int, default = 24\n        Number of residual channels in WaveNet architecture.\n    num_skip_channels : int, default = 32\n        Number of skip channels in WaveNet architecture, by default 32\n    dilation_depth : int or None, default = None\n        Number of dilation layers in WaveNet architecture. If set to None (default), dilation_depth is set such that\n        the receptive length is at least as long as the ``seasonality`` and at least ``2 * prediction_length``.\n    num_stacks : int, default = 1\n        Number of dilation stacks in WaveNet architecture.\n    temperature : float, default = 1.0\n        Temperature used for sampling from softmax distribution.\n    seasonality : int, optional\n        The seasonality of the time series. By default is set based on the ``freq`` of the data.\n    embedding_dimension : int, default = 5\n        The dimension of the embeddings for categorical features.\n    use_log_scale_feature : bool, default = True\n        If True, logarithm of the scale of the past data will be used as an additional static feature.\n    negative_data : bool, default = True\n        Flag indicating whether the time series take negative values.\n    max_cat_cardinality : int, default = 100\n        Maximum number of dimensions to use when one-hot-encoding categorical known_covariates.\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 64\n        Size of batches used during training\n    predict_batch_size : int, default = 500\n        Size of batches used during prediction.\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-3,\n        Learning rate used during training\n    trainer_kwargs : dict, optional\n        Optional keyword arguments passed to ``lightning.Trainer``.\n    early_stopping_patience : int or None, default = 20\n        Early stop training if the validation loss doesn\'t improve for this many epochs.\n    weight_decay : float, default = 1e-8\n        Weight decay regularization parameter.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    _supports_known_covariates = True\n    _supports_static_features = True\n    default_num_samples: int = 100\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.wavenet import WaveNetEstimator\n\n        return WaveNetEstimator\n\n    def _get_estimator_init_args(self) -> Dict[str, Any]:\n        init_kwargs = super()._get_estimator_init_args()\n        init_kwargs["num_feat_static_cat"] = self.num_feat_static_cat\n        init_kwargs["num_feat_static_real"] = self.num_feat_static_real\n        init_kwargs["cardinality"] = [1] if self.num_feat_static_cat == 0 else self.feat_static_cat_cardinality\n        init_kwargs["num_feat_dynamic_real"] = self.num_feat_dynamic_real\n        init_kwargs.setdefault("negative_data", self.negative_data)\n        init_kwargs.setdefault("seasonality", get_seasonality(self.freq))\n        init_kwargs.setdefault("time_features", get_time_features_for_frequency(self.freq))\n        init_kwargs.setdefault("num_parallel_samples", self.default_num_samples)\n        return init_kwargs\n\n\nclass TiDEModel(AbstractGluonTSModel):\n    """Time series dense encoder model from [Das2023]_.\n\n    Based on `gluonts.torch.model.tide.TiDEEstimator <https://ts.gluon.ai/stable/api/gluonts/gluonts.torch.model.tide.html>`_.\n    See GluonTS documentation for additional hyperparameters.\n\n\n    References\n    ----------\n    .. [Das2023] Das, Abhimanyu, et al.\n        "Long-term Forecasting with TiDE: Time-series Dense Encoder."\n        Transactions of Machine Learning Research. 2023.\n\n    Other Parameters\n    ----------------\n    context_length : int, default = max(64, 2 * prediction_length)\n        Number of past values used for prediction.\n    disable_static_features : bool, default = False\n        If True, static features won\'t be used by the model even if they are present in the dataset.\n        If False, static features will be used by the model if they are present in the dataset.\n    disable_known_covariates : bool, default = False\n        If True, known covariates won\'t be used by the model even if they are present in the dataset.\n        If False, known covariates will be used by the model if they are present in the dataset.\n    feat_proj_hidden_dim : int, default = 4\n        Size of the feature projection layer.\n    encoder_hidden_dim : int, default = 64\n        Size of the dense encoder layer.\n    decoder_hidden_dim : int, default = 64\n        Size of the dense decoder layer.\n    temporal_hidden_dim : int, default = 64\n        Size of the temporal decoder layer.\n    distr_hidden_dim : int, default = 64\n        Size of the distribution projection layer.\n    num_layers_encoder : int, default = 2\n        Number of layers in dense encoder.\n    num_layers_decoder : int, default = 2\n        Number of layers in dense decoder.\n    decoder_output_dim : int, default = 16\n        Output size of the dense decoder.\n    dropout_rate : float, default = 0.2\n        Dropout regularization parameter.\n    num_feat_dynamic_proj : int, default = 2\n        Output size of feature projection layer.\n    embedding_dimension : int, default = [16] * num_feat_static_cat\n        Dimension of the embeddings for categorical features\n    layer_norm : bool, default = True\n        Should layer normalization be enabled?\n    scaling : {"mean", "std", None}, default = "mean"\n        Scaling applied to each *context window* during training & prediction.\n        One of ``"mean"`` (mean absolute scaling), ``"std"`` (standardization), ``None`` (no scaling).\n\n        Note that this is different from the `target_scaler` that is applied to the *entire time series*.\n    max_epochs : int, default = 100\n        Number of epochs the model will be trained for\n    batch_size : int, default = 256\n        Size of batches used during training\n    predict_batch_size : int, default = 500\n        Size of batches used during prediction.\n    num_batches_per_epoch : int, default = 50\n        Number of batches processed every epoch\n    lr : float, default = 1e-4,\n        Learning rate used during training\n    trainer_kwargs : dict, optional\n        Optional keyword arguments passed to ``lightning.Trainer``.\n    early_stopping_patience : int or None, default = 20\n        Early stop training if the validation loss doesn\'t improve for this many epochs.\n    keep_lightning_logs : bool, default = False\n        If True, ``lightning_logs`` directory will NOT be removed after the model finished training.\n    """\n\n    _supports_known_covariates = True\n    _supports_static_features = True\n\n    def _get_estimator_class(self) -> Type[GluonTSEstimator]:\n        from gluonts.torch.model.tide import TiDEEstimator\n\n        return TiDEEstimator\n\n    def _get_default_params(self):\n        return super()._get_default_params() | {\n            "context_length": min(512, max(64, 2 * self.prediction_length)),\n            "encoder_hidden_dim": 64,\n            "decoder_hidden_dim": 64,\n            "temporal_hidden_dim": 64,\n            "distr_hidden_dim": 64,\n            "num_layers_encoder": 2,\n            "num_layers_decoder": 2,\n            "decoder_output_dim": 16,\n            "dropout_rate": 0.2,\n            "layer_norm": True,\n            "lr": 1e-4,\n            "batch_size": 256,\n        }\n\n    def _get_estimator_init_args(self) -> Dict[str, Any]:\n        init_kwargs = super()._get_estimator_init_args()\n        init_kwargs["num_feat_static_cat"] = self.num_feat_static_cat\n        init_kwargs["num_feat_static_real"] = self.num_feat_static_real\n        init_kwargs["cardinality"] = self.feat_static_cat_cardinality\n        init_kwargs["num_feat_dynamic_real"] = self.num_feat_dynamic_real\n        return init_kwargs\n',
            'timeseries/tests/unittests/models/test_gluonts.py': 'from pathlib import Path\nfrom unittest import mock\n\nimport numpy as np\nimport pytest\nfrom gluonts.model.predictor import Predictor as GluonTSPredictor\n\nfrom autogluon.timeseries.models.gluonts import (\n    DeepARModel,\n    DLinearModel,\n    PatchTSTModel,\n    SimpleFeedForwardModel,\n    TemporalFusionTransformerModel,\n)\nfrom autogluon.timeseries.utils.features import TimeSeriesFeatureGenerator\n\nfrom ..common import (\n    DATAFRAME_WITH_COVARIATES,\n    DATAFRAME_WITH_STATIC,\n    DUMMY_TS_DATAFRAME,\n    get_data_frame_with_covariates,\n)\n\nDUMMY_HYPERPARAMETERS = {"max_epochs": 1, "num_batches_per_epoch": 1}\n\n\ndef test_when_context_length_is_not_set_then_default_context_length_is_used(gluonts_model_class):\n    data = DUMMY_TS_DATAFRAME\n    model = gluonts_model_class(freq=data.freq)\n    model.fit(train_data=data)\n    estimator_init_args = model._get_estimator_init_args()\n    default_context_length = model._get_default_params()["context_length"]\n    assert estimator_init_args["context_length"] == default_context_length\n\n\ndef test_when_context_length_is_set_then_provided_context_length_is_used(gluonts_model_class):\n    data = DUMMY_TS_DATAFRAME\n    model = gluonts_model_class(freq=data.freq, hyperparameters={"context_length": 1337})\n    model.fit(train_data=data)\n    estimator_init_args = model._get_estimator_init_args()\n    assert estimator_init_args["context_length"] == 1337\n\n\n@pytest.mark.parametrize("time_limit", [10, None])\ndef test_given_time_limit_when_fit_called_then_models_train_correctly(\n    gluonts_model_class, time_limit, temp_model_path\n):\n    model = gluonts_model_class(\n        path=temp_model_path,\n        freq="h",\n        prediction_length=5,\n        hyperparameters={"max_epochs": 2},\n    )\n\n    assert not model.gts_predictor\n    model.fit(train_data=DUMMY_TS_DATAFRAME, time_limit=time_limit)\n    assert isinstance(model.gts_predictor, GluonTSPredictor)\n\n\n# @flaky(max_runs=3)\n# @pytest.mark.timeout(4)\n@pytest.mark.skip(reason="Timeout spuriously fails in CI")\ndef test_given_low_time_limit_when_fit_called_then_model_training_does_not_exceed_time_limit(\n    gluonts_model_class, temp_model_path\n):\n    model = gluonts_model_class(\n        path=temp_model_path,\n        freq="h",\n        prediction_length=5,\n        hyperparameters={"max_epochs": 20000},\n    )\n\n    assert not model.gts_predictor\n    model.fit(train_data=DUMMY_TS_DATAFRAME, time_limit=2)\n    assert isinstance(model.gts_predictor, GluonTSPredictor)\n\n\ndef test_when_models_saved_then_gluonts_predictors_can_be_loaded(gluonts_model_class, temp_model_path):\n    model = gluonts_model_class(\n        path=temp_model_path,\n        freq="h",\n        quantile_levels=[0.1, 0.9],\n    )\n    model.fit(\n        train_data=DUMMY_TS_DATAFRAME,\n    )\n    model.save()\n\n    loaded_model = model.__class__.load(path=model.path)\n\n    assert model._get_estimator_class() is loaded_model._get_estimator_class()\n    assert loaded_model.gts_predictor.to(model.gts_predictor.device) == model.gts_predictor\n\n\n@pytest.fixture(scope="module")\ndef df_with_static():\n    feature_generator = TimeSeriesFeatureGenerator(target="target", known_covariates_names=[])\n    df = DATAFRAME_WITH_STATIC.copy(deep=False)\n    df = feature_generator.fit_transform(df)\n    return df, feature_generator.covariate_metadata\n\n\n@pytest.fixture(scope="module")\ndef df_with_covariates():\n    known_covariates_names = [col for col in DATAFRAME_WITH_COVARIATES.columns if col != "target"]\n    feature_generator = TimeSeriesFeatureGenerator(target="target", known_covariates_names=known_covariates_names)\n    df = DATAFRAME_WITH_COVARIATES.copy(deep=False)\n    df = feature_generator.fit_transform(df)\n    return df, feature_generator.covariate_metadata\n\n\ndef test_when_static_features_present_then_they_are_passed_to_dataset(\n    gluonts_model_with_static_features_class, df_with_static\n):\n    df, metadata = df_with_static\n    model = gluonts_model_with_static_features_class(metadata=metadata, freq=df.freq)\n    with mock.patch(\n        "autogluon.timeseries.models.gluonts.abstract_gluonts.SimpleGluonTSDataset.__init__"\n    ) as patch_dataset:\n        try:\n            model.fit(train_data=df)\n        except TypeError:\n            pass\n        finally:\n            call_kwargs = patch_dataset.call_args[1]\n            feat_static_cat = call_kwargs["feat_static_cat"]\n            feat_static_real = call_kwargs["feat_static_real"]\n            assert feat_static_cat.dtype == "int64"\n            assert feat_static_real.dtype == "float32"\n\n\ndef test_given_fit_with_static_features_when_predicting_then_static_features_are_used(\n    gluonts_model_with_static_features_class, df_with_static\n):\n    df, metadata = df_with_static\n    model = gluonts_model_with_static_features_class(metadata=metadata, freq=df.freq)\n    model.fit(train_data=df)\n    predictor_method = "gluonts.torch.model.predictor.PyTorchPredictor.predict"\n    with mock.patch(predictor_method) as mock_predict:\n        try:\n            model.predict(df)\n        except IndexError:  # expected because of mock\n            pass\n        finally:\n            gluonts_dataset = mock_predict.call_args[1]["dataset"]\n            item = next(iter(gluonts_dataset))\n            assert item["feat_static_cat"].shape == (1,)\n            assert item["feat_static_real"].shape == (2,)\n\n\ndef test_when_static_features_present_then_model_attributes_set_correctly(\n    gluonts_model_with_static_features_class, df_with_static\n):\n    df, metadata = df_with_static\n    model = gluonts_model_with_static_features_class(metadata=metadata, freq=df.freq)\n    model.fit(train_data=df)\n    assert model.num_feat_static_cat > 0\n    assert model.num_feat_static_real > 0\n    assert len(model.feat_static_cat_cardinality) == model.num_feat_static_cat\n    assert 1 <= model.feat_static_cat_cardinality[0] <= 4\n\n\ndef test_when_disable_static_features_set_to_true_then_static_features_are_not_used(\n    gluonts_model_with_static_features_class, df_with_static\n):\n    df, metadata = df_with_static\n    model = gluonts_model_with_static_features_class(\n        hyperparameters={"disable_static_features": True}, metadata=metadata, freq=df.freq\n    )\n    with mock.patch(\n        "autogluon.timeseries.models.gluonts.abstract_gluonts.SimpleGluonTSDataset.__init__"\n    ) as patch_dataset:\n        try:\n            model.fit(train_data=df)\n        except TypeError:\n            pass\n        finally:\n            call_kwargs = patch_dataset.call_args[1]\n            feat_static_cat = call_kwargs["feat_static_cat"]\n            feat_static_real = call_kwargs["feat_static_real"]\n            assert feat_static_cat is None\n            assert feat_static_real is None\n\n\ndef test_when_known_covariates_present_then_they_are_passed_to_dataset(\n    gluonts_model_with_static_features_class, df_with_covariates\n):\n    df, metadata = df_with_covariates\n    model = gluonts_model_with_static_features_class(metadata=metadata, freq=df.freq)\n    with mock.patch(\n        "autogluon.timeseries.models.gluonts.abstract_gluonts.SimpleGluonTSDataset.__init__"\n    ) as patch_dataset:\n        try:\n            model.fit(train_data=df)\n        except TypeError:\n            pass\n        finally:\n            call_kwargs = patch_dataset.call_args[1]\n            feat_dynamic_real = call_kwargs["feat_dynamic_real"]\n            assert feat_dynamic_real.dtype == "float32"\n\n\ndef test_when_known_covariates_present_then_model_attributes_set_correctly(\n    gluonts_model_with_known_covariates_class, df_with_covariates\n):\n    df, metadata = df_with_covariates\n    model = gluonts_model_with_known_covariates_class(metadata=metadata, freq=df.freq)\n    model.fit(train_data=df)\n    assert model.num_feat_dynamic_real > 0\n\n\ndef test_when_known_covariates_present_for_predict_then_covariates_have_correct_shape(\n    gluonts_model_with_known_covariates_class, df_with_covariates\n):\n    df, metadata = df_with_covariates\n    prediction_length = 5\n    past_data, known_covariates = df.get_model_inputs_for_scoring(prediction_length, metadata.known_covariates)\n    model = gluonts_model_with_known_covariates_class(\n        metadata=metadata, freq=df.freq, prediction_length=prediction_length\n    )\n    model.fit(train_data=past_data)\n    for ts in model._to_gluonts_dataset(past_data, known_covariates=known_covariates):\n        expected_length = len(ts["target"]) + prediction_length\n        if model.supports_cat_covariates:\n            assert ts["feat_dynamic_cat"].shape == (len(metadata.known_covariates_cat), expected_length)\n            assert ts["feat_dynamic_real"].shape == (len(metadata.known_covariates_real), expected_length)\n        else:\n            num_onehot_columns = past_data[metadata.known_covariates_cat].nunique().sum()\n            expected_num_feat_dynamic_real = len(metadata.known_covariates_real) + num_onehot_columns\n            assert ts["feat_dynamic_real"].shape == (expected_num_feat_dynamic_real, expected_length)\n\n\ndef test_when_disable_known_covariates_set_to_true_then_known_covariates_are_not_used(\n    gluonts_model_with_known_covariates_class, df_with_covariates\n):\n    df, metadata = df_with_covariates\n    model = gluonts_model_with_known_covariates_class(\n        hyperparameters={"disable_known_covariates": True}, metadata=metadata, freq=df.freq\n    )\n    with mock.patch(\n        "autogluon.timeseries.models.gluonts.abstract_gluonts.SimpleGluonTSDataset.__init__"\n    ) as patch_dataset:\n        try:\n            model.fit(train_data=df)\n        except TypeError:\n            pass\n        finally:\n            call_kwargs = patch_dataset.call_args[1]\n            assert call_kwargs["feat_dynamic_real"] is None\n            assert call_kwargs["feat_dynamic_cat"] is None\n\n\ndef test_when_static_and_dynamic_covariates_present_then_model_trains_normally(\n    gluonts_model_with_known_covariates_and_static_features_class,\n):\n    dataframe_with_static_and_covariates = DATAFRAME_WITH_STATIC.copy()\n    known_covariates_names = ["cov1", "cov2"]\n    for col_name in known_covariates_names:\n        dataframe_with_static_and_covariates[col_name] = np.random.normal(\n            size=len(dataframe_with_static_and_covariates)\n        )\n\n    gen = TimeSeriesFeatureGenerator(target="target", known_covariates_names=known_covariates_names)\n    df = gen.fit_transform(dataframe_with_static_and_covariates)\n\n    model = gluonts_model_with_known_covariates_and_static_features_class(\n        metadata=gen.covariate_metadata, freq=df.freq\n    )\n    model.fit(train_data=df)\n    model.score_and_cache_oof(df)\n\n\n@pytest.mark.parametrize("predict_batch_size", [30, 200])\ndef test_given_custom_predict_batch_size_then_predictor_uses_correct_batch_size(predict_batch_size):\n    model = PatchTSTModel(\n        hyperparameters={"predict_batch_size": predict_batch_size, **DUMMY_HYPERPARAMETERS},\n        freq=DUMMY_TS_DATAFRAME.freq,\n    )\n    model.fit(train_data=DUMMY_TS_DATAFRAME)\n    assert model.gts_predictor.batch_size == predict_batch_size  # type: ignore\n\n\ndef catch_trainer_kwargs(model):\n    with mock.patch("lightning.pytorch.Trainer") as mock_trainer:\n        try:\n            model.fit(train_data=DUMMY_TS_DATAFRAME, val_data=DUMMY_TS_DATAFRAME)\n        except IsADirectoryError:\n            # Training fails because Trainer is a mock object\n            pass\n    return mock_trainer.call_args[1]\n\n\ndef test_when_custom_callbacks_passed_via_trainer_kwargs_then_trainer_receives_them():\n    from lightning.pytorch.callbacks import RichModelSummary\n\n    callback = RichModelSummary()\n    model = DLinearModel(\n        hyperparameters={"trainer_kwargs": {"callbacks": [callback]}},\n        freq=DUMMY_TS_DATAFRAME.freq,\n    )\n    received_trainer_kwargs = catch_trainer_kwargs(model)\n    assert any(isinstance(cb, RichModelSummary) for cb in received_trainer_kwargs["callbacks"])\n\n\ndef test_when_early_stopping_patience_provided_then_early_stopping_callback_created():\n    from lightning.pytorch.callbacks import EarlyStopping\n\n    patience = 7\n    model = SimpleFeedForwardModel(\n        hyperparameters={"early_stopping_patience": patience, **DUMMY_HYPERPARAMETERS},\n        freq=DUMMY_TS_DATAFRAME.freq,\n    )\n    received_trainer_kwargs = catch_trainer_kwargs(model)\n    es_callbacks = [cb for cb in received_trainer_kwargs["callbacks"] if isinstance(cb, EarlyStopping)]\n    assert len(es_callbacks) == 1\n    assert es_callbacks[0].patience == patience\n\n\ndef test_when_early_stopping_patience_is_none_then_early_stopping_callback_not_created():\n    from lightning.pytorch.callbacks import EarlyStopping\n\n    model = SimpleFeedForwardModel(\n        hyperparameters={"early_stopping_patience": None, **DUMMY_HYPERPARAMETERS},\n        freq=DUMMY_TS_DATAFRAME.freq,\n    )\n    received_trainer_kwargs = catch_trainer_kwargs(model)\n    es_callbacks = [cb for cb in received_trainer_kwargs["callbacks"] if isinstance(cb, EarlyStopping)]\n    assert len(es_callbacks) == 0\n\n\ndef test_when_custom_trainer_kwargs_given_then_trainer_receives_them():\n    trainer_kwargs = {"max_epochs": 5, "limit_train_batches": 100}\n    model = PatchTSTModel(\n        hyperparameters={"trainer_kwargs": trainer_kwargs, **DUMMY_HYPERPARAMETERS},\n        freq=DUMMY_TS_DATAFRAME.freq,\n    )\n    received_trainer_kwargs = catch_trainer_kwargs(model)\n    for k, v in trainer_kwargs.items():\n        assert received_trainer_kwargs[k] == v\n\n\ndef test_when_model_finishes_training_then_logs_are_removed(temp_model_path):\n    model = TemporalFusionTransformerModel(\n        freq=DUMMY_TS_DATAFRAME.freq, path=temp_model_path, hyperparameters=DUMMY_HYPERPARAMETERS\n    )\n    model.fit(train_data=DUMMY_TS_DATAFRAME)\n    assert not (Path(model.path) / "lightning_logs").exists()\n\n\n@pytest.mark.parametrize("keep_lightning_logs", [True, False])\ndef test_when_keep_lightning_logs_set_then_logs_are_not_removed(keep_lightning_logs, temp_model_path):\n    model = DeepARModel(\n        freq=DUMMY_TS_DATAFRAME.freq,\n        path=temp_model_path,\n        hyperparameters={"keep_lightning_logs": keep_lightning_logs, **DUMMY_HYPERPARAMETERS},\n    )\n    model.fit(train_data=DUMMY_TS_DATAFRAME)\n    assert (Path(model.path) / "lightning_logs").exists() == keep_lightning_logs\n\n\n@pytest.mark.parametrize("known_covariates_real", [["known_real_1", "known_real_2"], []])\n@pytest.mark.parametrize("past_covariates_real", [["past_real_1"], []])\n@pytest.mark.parametrize("static_features_real", [["static_real_1", "static_real_2"], []])\ndef test_given_features_present_when_model_is_fit_then_feature_transformer_is_present(\n    gluonts_model_class, temp_model_path, known_covariates_real, past_covariates_real, static_features_real\n):\n    known_covariates_names = known_covariates_real + ["known_cat_1"]\n    feat_generator = TimeSeriesFeatureGenerator(target="target", known_covariates_names=known_covariates_names)\n    data = get_data_frame_with_covariates(\n        covariates_cat=["known_cat_1"],\n        covariates_real=known_covariates_real + past_covariates_real,\n        static_features_real=static_features_real,\n        static_features_cat=["static_cat_1"],\n    )\n    data = feat_generator.fit_transform(data)\n    model = gluonts_model_class(\n        freq=data.freq,\n        path=temp_model_path,\n        metadata=feat_generator.covariate_metadata,\n    )\n    model.fit(train_data=data, val_data=data)\n    covariate_scaler = model.covariate_scaler\n\n    if len(known_covariates_real) > 0 and model.supports_known_covariates:\n        assert len(covariate_scaler._column_transformers["known"].feature_names_in_) > 0\n    else:\n        assert "known" not in covariate_scaler._column_transformers\n\n    if len(past_covariates_real) > 0 and model.supports_past_covariates:\n        assert len(covariate_scaler._column_transformers["past"].feature_names_in_) > 0\n    else:\n        assert "past" not in covariate_scaler._column_transformers\n\n    if len(static_features_real) > 0 and model.supports_static_features:\n        assert len(covariate_scaler._column_transformers["static"].feature_names_in_) > 0\n    else:\n        assert "static" not in covariate_scaler._column_transformers\n\n\ndef test_when_model_is_initialized_then_covariate_scaler_is_created(gluonts_model_class, df_with_covariates):\n    df, metadata = df_with_covariates\n    model = gluonts_model_class(freq=df.freq, metadata=metadata)\n    model.initialize()\n    assert model.covariate_scaler is not None\n',
        }
